========== versions.tf ==========
# DataQ harness — Terraform / provider version pins.
# Disposable demo env (ADR 0021). Local state backend — state is gitignored,
# never committed (it contains secrets). Pin providers; do not float to latest.

terraform {
  required_version = ">= 1.9"

  backend "local" {
    path = "terraform.tfstate"
  }

  required_providers {
    azurerm = {
      source  = "hashicorp/azurerm"
      version = "~> 4.0"
    }
    snowflake = {
      source  = "snowflakedb/snowflake"
      version = "~> 1.0"
    }
    databricks = {
      source  = "databricks/databricks"
      version = "~> 1.50"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.6"
    }
  }
}
========== providers.tf ==========
# Provider blocks. No credentials live in these files — every provider reads
# its secrets from the environment exported by `source ../secrets.sh`:
#   azurerm    -> ARM_SUBSCRIPTION_ID / ARM_TENANT_ID / ARM_CLIENT_ID / ARM_CLIENT_SECRET
#   snowflake  -> SNOWFLAKE_USER / SNOWFLAKE_PASSWORD / SNOWFLAKE_ROLE
#   databricks -> DATABRICKS_HOST / DATABRICKS_TOKEN
# Only non-secret identifiers (org/account name) are passed as variables.

provider "azurerm" {
  features {}
  # subscription_id / tenant_id / client_id / client_secret come from ARM_* env vars.
  #
  # The Terraform SP is Contributor on dataq-rg ONLY — it has no rights at the
  # subscription scope, so it cannot auto-register resource providers. Skip that;
  # the required RPs (Microsoft.Storage, Microsoft.DataFactory) must already be
  # registered on the subscription by an owner (see README).
  resource_provider_registrations = "none"
}

provider "snowflake" {
  # user / password / role come from SNOWFLAKE_* env vars.
  organization_name = var.snowflake_organization_name
  account_name      = var.snowflake_account_name
  # snowflake_table is still a preview resource in the provider.
  preview_features_enabled = ["snowflake_table_resource"]
}

provider "databricks" {
  # host / token come from DATABRICKS_HOST / DATABRICKS_TOKEN env vars.
  # Pin PAT auth explicitly — the ARM_* env vars (for azurerm) would otherwise be
  # picked up as a second, conflicting auth method (Azure SP).
  auth_type = "pat"
}

provider "random" {}
========== main.tf ==========
# Shared data sources + locals.

# The RG already exists (§0); the SP has Contributor on it. Reference, don't create.
data "azurerm_resource_group" "dataq" {
  name = var.azure_resource_group
}

# Random suffix to make the storage-account name globally unique.
resource "random_string" "suffix" {
  length  = 6
  lower   = true
  upper   = false
  numeric = true
  special = false
}

locals {
  common_tags = {
    project = var.project_tag
    managed = "terraform"
    purpose = "dataq-harness"
  }

  # 3-24 lowercase alphanumerics; prefix + 6-char suffix.
  storage_account_name = substr("${var.storage_account_prefix}${random_string.suffix.result}", 0, 24)
}
========== variables.tf ==========
# Non-secret configuration. Defaults match the §0 prerequisites in HARNESS_TODO.md.
# Override in terraform.tfvars (also gitignored) if you stand up a second env.

variable "project_tag" {
  description = "Tag applied to all cloud resources (secrets.sh convention: project=dataq)."
  type        = string
  default     = "dataq"
}

# ---- Azure ----------------------------------------------------------------

variable "azure_resource_group" {
  description = "Existing RG the Terraform SP has Contributor on (created in §0)."
  type        = string
  default     = "dataq-rg"
}

variable "azure_location" {
  description = "Azure region for harness resources."
  type        = string
  default     = "West US 2"
}

variable "postgres_location" {
  description = "Region for the Airflow metadata Postgres. Separate from azure_location because Postgres Flexible Server is offer-restricted in West US 2 for this subscription. Use westus3 (adjacent to West US 2 — low latency the Airflow scheduler needs; centralus's ~30-40ms cross-region latency starved the scheduler's executor loop)."
  type        = string
  default     = "westus3"
}

variable "storage_account_prefix" {
  description = "ADLS Gen2 account name prefix (a random suffix is appended for global uniqueness; 3-24 lowercase alphanumerics total)."
  type        = string
  default     = "dataqharness"
}

variable "adls_filesystems" {
  description = "ADLS Gen2 filesystems (containers) for the landing zone."
  type        = list(string)
  default     = ["landing", "raw"]
}

variable "adf_factory_name" {
  description = "Azure Data Factory instance name (Flow A load pipelines)."
  type        = string
  default     = "dataq-harness-adf"
}

# ---- Snowflake ------------------------------------------------------------
# Account identifier PVQSOEQ-ZGB34383 = <organization>-<account_name>.

variable "snowflake_organization_name" {
  description = "Snowflake organization name (the part before the dash in the account locator)."
  type        = string
  default     = "PVQSOEQ"
}

variable "snowflake_account_name" {
  description = "Snowflake account name (the part after the dash in the account locator)."
  type        = string
  default     = "ZGB34383"
}

variable "snowflake_database" {
  description = "Database DataQ writes the warehouse-loaded retail datasets into (Flow A)."
  type        = string
  default     = "DATAQ_DB"
}

variable "snowflake_warehouse" {
  description = "Virtual warehouse DataQ runs checks on."
  type        = string
  default     = "DATAQ_WH"
}

variable "snowflake_reader_role" {
  description = "Least-privilege role DataQ uses to read (granted to the existing user, no new password)."
  type        = string
  default     = "DATAQ_READER"
}

variable "snowflake_reader_user" {
  description = "Existing Snowflake user the reader role is granted to (DataQ connects as this user)."
  type        = string
  default     = "ROYARIJIT04"
}

variable "snowflake_schemas" {
  description = "Schemas created in the DataQ database (Flow A warehouse datasets)."
  type        = list(string)
  default     = ["RETAIL"]
}

# ---- Databricks / Unity Catalog ------------------------------------------

variable "uc_catalog" {
  description = "Unity Catalog catalog for the harness retail data."
  type        = string
  default     = "dataq_retail"
}

variable "uc_schemas" {
  description = "Medallion + reference schemas in the UC catalog."
  type        = list(string)
  default     = ["raw", "silver", "gold", "reference"]
}

# ---- Container Apps platform (Airflow host + mockdata Job) -----------------

variable "acr_prefix" {
  description = "Container registry name prefix (a random suffix is appended; 5-50 alphanumerics, globally unique)."
  type        = string
  default     = "dataqacr"
}

variable "log_retention_days" {
  description = "Log Analytics retention for the Container Apps Environment."
  type        = number
  default     = 30
}

variable "databricks_host" {
  description = "Databricks workspace URL (for the Airflow UC loads / Flow B notebook submit)."
  type        = string
  default     = ""
}

variable "databricks_token" {
  description = "Databricks PAT for the Airflow UC loads (set via TF_VAR_databricks_token=$DATABRICKS_TOKEN)."
  type        = string
  default     = ""
  sensitive   = true
}

variable "databricks_http_path" {
  description = "Databricks SQL warehouse HTTP path (e.g. /sql/1.0/warehouses/<id>) for databricks-sql UC loads."
  type        = string
  default     = ""
}

variable "airflow_image_tag" {
  description = "Tag of the custom airflow-dataq image in ACR (apache/airflow + harness DAGs + client libs). Use an IMMUTABLE tag, not 'latest' — Container Apps caches 'latest' at the node, so a same-tag rebuild won't be re-pulled on a new revision. Bump this on every DAG/image change."
  type        = string
  default     = "v202606271801"
}

variable "airflow_image" {
  description = "Airflow image. Defaults to the public image (no custom DAGs); swap to the registry image once §3 bakes DAGs in."
  type        = string
  default     = "apache/airflow:2.10.5"
}

variable "airflow_admin_user" {
  description = "Airflow web admin username (password is generated, see output)."
  type        = string
  default     = "admin"
}

variable "mockdata_image_tag" {
  description = "Tag of the mockdata image in the registry the cron Jobs run (build+push before the first scheduled run)."
  type        = string
  default     = "latest"
}

variable "postgres_admin_login" {
  description = "Airflow metadata Postgres admin login."
  type        = string
  default     = "airflowadmin"
}

variable "postgres_sku" {
  description = "Postgres Flexible Server SKU (Burstable B1ms = cheapest)."
  type        = string
  default     = "B_Standard_B1ms"
}

variable "snowflake_password" {
  description = "Snowflake password for the ADF Snowflake linked service (set via TF_VAR_snowflake_password=$SNOWFLAKE_PASSWORD)."
  type        = string
  default     = ""
  sensitive   = true
}

variable "snowflake_loader_role" {
  description = "Snowflake role the harness ETL (Airflow + ADF) loads with — CREATE TABLE + write DML, distinct from the read-only DATAQ_READER DataQ checks with."
  type        = string
  default     = "DATAQ_LOADER"
}

variable "dataq_webhook_base_url" {
  description = "DataQ public base URL the ADF Web activity / Airflow callback post to (e.g. https://dataq.example.com). Empty until DataQ is deployed."
  type        = string
  default     = ""
}

variable "dataq_adf_webhook_secret" {
  description = "Shared secret in the ADF webhook URL (ADR 0006) — the same value DataQ stores. Set via TF_VAR_dataq_adf_webhook_secret."
  type        = string
  default     = ""
  sensitive   = true
}

variable "feed_crons" {
  description = "Per-feed cron (UTC, 5-field) for the mockdata file-creation Jobs (§2a). Offset BEFORE the ADF/Airflow scheduled loads."
  type        = map(string)
  default = {
    orders    = "0 0,6,12,18 * * *" # 4x/day
    tracking  = "0 0,12 * * *"      # 2x/day
    inventory = "0 1 * * *"         # daily 01:00
    feedback  = "0 1 */2 * *"       # every 2 days
    supply    = "30 0 * * *"        # inbound purchase orders, daily 00:30
  }
}
