output "snowflake_database" {
  description = "-> fill SNOWFLAKE_DATABASE in secrets.sh."
  value       = snowflake_database.dataq.name
}

output "snowflake_warehouse" {
  description = "-> fill SNOWFLAKE_WAREHOUSE in secrets.sh."
  value       = snowflake_warehouse.dataq.name
}

output "snowflake_reader_role" {
  description = "Least-privilege role -> switch SNOWFLAKE_ROLE in secrets.sh once tables are loaded."
  value       = snowflake_account_role.reader.name
}

output "snowflake_schemas" {
  description = "Schemas created in the DataQ database."
  value       = [for s in snowflake_schema.schemas : s.name]
}

output "uc_catalog" {
  description = "Unity Catalog catalog name (DataQ UC connection)."
  value       = databricks_catalog.dataq.name
}

output "uc_schemas" {
  description = "UC schemas (medallion + reference)."
  value       = [for s in databricks_schema.schemas : s.name]
}

# ---- Container Apps platform ----------------------------------------------

output "container_app_environment" {
  description = "Shared Container Apps Environment (Airflow + mockdata Jobs)."
  value       = azurerm_container_app_environment.harness.name
}

output "acr_login_server" {
  description = "Registry login server — build+push the mockdata image here before the first Job run."
  value       = azurerm_container_registry.harness.login_server
}

output "airflow_url" {
  description = "Airflow web UI."
  value       = "https://${azurerm_container_app.airflow.ingress[0].fqdn}"
}

output "airflow_admin_user" {
  description = "Airflow web admin username."
  value       = var.airflow_admin_user
}

output "airflow_admin_password" {
  description = "Airflow web admin password (generated)."
  value       = random_password.airflow_admin.result
  sensitive   = true
}

output "postgres_fqdn" {
  description = "Airflow metadata Postgres host."
  value       = azurerm_postgresql_flexible_server.airflow.fqdn
}

output "mockdata_jobs" {
  description = "Cron Jobs created (feed -> schedule)."
  value       = { for k, j in azurerm_container_app_job.mockdata : k => var.feed_crons[k] }
}
