========== airflow.tf ==========
# Airflow on Container Apps — scheduler + webserver (LocalExecutor), backed by the
# Postgres metadata DB. min_replicas = 1 (the scheduler can't scale to zero); HTTPS
# ingress so Event-Grid (file-landing push) and DataQ can reach it. ~$25-75/mo always-on.
#
# Starts on the public airflow image (no DAGs). §3 swaps `airflow_image` for a custom
# registry image (FROM apache/airflow + COPY dags/) that calls the mockdata tick CLI / loads.

resource "random_id" "fernet" {
  byte_length = 32
}

resource "random_password" "airflow_webserver_secret" {
  length  = 32
  special = false
}

resource "random_password" "airflow_admin" {
  length  = 20
  special = false
}

locals {
  # Valid Fernet key = url-safe base64 of 32 bytes (swap +/ for -_, keep padding).
  airflow_fernet_key = replace(replace(random_id.fernet.b64_std, "+", "-"), "/", "_")

  airflow_pg_conn = join("", [
    "postgresql+psycopg2://",
    var.postgres_admin_login, ":", random_password.pg.result,
    "@", azurerm_postgresql_flexible_server.airflow.fqdn, ":5432/",
    azurerm_postgresql_flexible_server_database.airflow.name, "?sslmode=require",
  ])

  # Custom registry image (apache/airflow + the harness DAGs + client libs).
  airflow_image = "${azurerm_container_registry.harness.login_server}/airflow-dataq:${var.airflow_image_tag}"

  # CeleryExecutor: Redis broker (internal) + Postgres result backend. Workers run in a
  # SEPARATE, horizontally scalable container app (airflow_worker.tf) — that's what lifts
  # the single-executor / 2-vCPU-per-replica ceiling that throttled LocalExecutor.
  # Container Apps internal service-to-service: the short app name resolves over the
  # environment's internal DNS (the full .internal. FQDN did not connect for TCP).
  celery_broker_url = "redis://${azurerm_container_app.redis.name}:6379/0"
  celery_result_backend = join("", [
    "db+postgresql://",
    var.postgres_admin_login, ":", random_password.pg.result,
    "@", azurerm_postgresql_flexible_server.airflow.fqdn, ":5432/",
    azurerm_postgresql_flexible_server_database.airflow.name, "?sslmode=require",
  ])

  # Shared scheduler + webserver env (DRYed into both containers via dynamic blocks).
  # LocalExecutor runs tasks in the scheduler, so the connection env must live here.
  airflow_env = [
    { name = "AIRFLOW__DATABASE__SQL_ALCHEMY_CONN", secret_name = "pg-conn" },
    { name = "AIRFLOW__CORE__EXECUTOR", value = "CeleryExecutor" },
    { name = "AIRFLOW__CELERY__BROKER_URL", value = local.celery_broker_url },
    { name = "AIRFLOW__CELERY__RESULT_BACKEND", secret_name = "celery-result-backend" },
    # Tasks per worker replica — each cold-starts a fresh interpreter, so keep it modest
    # vs the worker's 2 vCPU / 4 GiB; horizontal scaling (more replicas) is the lever.
    { name = "AIRFLOW__CELERY__WORKER_CONCURRENCY", value = "3" },
    { name = "AIRFLOW__CORE__FERNET_KEY", secret_name = "fernet-key" },
    { name = "AIRFLOW__WEBSERVER__SECRET_KEY", secret_name = "webserver-secret" },
    { name = "AIRFLOW__CORE__LOAD_EXAMPLES", value = "False" },
    # Enable basic-auth on the REST API so DAG runs can be triggered programmatically.
    { name = "AIRFLOW__API__AUTH_BACKENDS", value = "airflow.api.auth.backend.basic_auth,airflow.api.auth.backend.session" },
    # Run each task in a FRESH interpreter (spawn) instead of forking the scheduler.
    # The scheduler is multi-threaded (Azure SDK / gRPC bg threads); LocalExecutor's
    # fork() of it deadlocks the child → tasks stick in 'scheduled' and never run.
    { name = "AIRFLOW__CORE__EXECUTE_TASKS_NEW_PYTHON_INTERPRETER", value = "True" },

    # ADLS read (key-based connection string).
    { name = "AZURE_STORAGE_CONNECTION_STRING", secret_name = "adls-conn" },
    { name = "ADLS_FILESYSTEM", value = var.adls_filesystems[0] },

    # Snowflake load — write with DATAQ_LOADER (ETL), not the read-only DATAQ_READER.
    { name = "SNOWFLAKE_ACCOUNT", value = "${var.snowflake_organization_name}-${var.snowflake_account_name}" },
    { name = "SNOWFLAKE_USER", value = var.snowflake_reader_user },
    { name = "SNOWFLAKE_PASSWORD", secret_name = "snowflake-password" },
    { name = "SNOWFLAKE_WAREHOUSE", value = var.snowflake_warehouse },
    { name = "SNOWFLAKE_DATABASE", value = var.snowflake_database },
    { name = "SNOWFLAKE_SCHEMA", value = var.snowflake_schemas[0] },
    { name = "SNOWFLAKE_ROLE", value = var.snowflake_loader_role },

    # Databricks — UC reference loads (flow_a_uc_reference) + Flow B notebook submit.
    { name = "DATABRICKS_HOST", value = var.databricks_host },
    { name = "DATABRICKS_TOKEN", secret_name = "databricks-token" },
    { name = "DATABRICKS_HTTP_PATH", value = var.databricks_http_path },
    { name = "UC_CATALOG", value = var.uc_catalog },
  ]
}

