}

# ── Sensitive ────────────────────────────────────────────────────────────────
output "swa_api_token" {
  description = "-> repo secret AZURE_STATIC_WEB_APPS_API_TOKEN (read with: terraform output -raw swa_api_token)."
  value       = azurerm_static_web_app.app.api_key
